        # SPA ǰ��·�ɻ���
        return FileResponse(_INDEX_HTML)

    # WebSocket �˵�
    @app.websocket("/ws")
    async def websocket_endpoint(ws: WebSocket) -> None:
        await ws.accept()
        client_id = id(ws)

